?><main class="main-content"><?php require ROOT_PATH.'/includes/navbar.php';?><section class="page-heading page-section"><h1 class="page-title">Document vault · <?=e($vehicle['registration_number'])?></h1></section><section class="grid grid-2"><form class="card dashboard-card" method="post" enctype="multipart/form-data"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><div class="form-group"><label>Document type</label><select name="document_type"><?php foreach(['Registration Certificate','Insurance','Fitness Certificate','Permit','Pollution Certificate','Other'] as $type):?><option><?=e($type)?></option><?php endforeach;?></select></div><div class="form-group"><label>File</label><input type="file" name="document" accept=".pdf,.jpg,.jpeg,.png" required></div><button class="btn btn-primary">Upload document</button></form><article class="card dashboard-card"><h2>Stored documents</h2><ul class="document-list"><?php foreach($documents as $document):?><li><i class="fa fa-file"></i><a href="<?=e(siteUrl($document['file_path']))?>" target="_blank" rel="noopener"><?=e($document['document_type'])?></a><small><?=e(formatDate($document['created_at']))?></small></li><?php endforeach;?><?php if(!$documents):?><li>No documents uploaded.</li><?php endif;?></ul></article></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
